let DATA={items:[],categories:[],ropes:[],pieces:[],loans:[],inventories:[],inventory_items:[],procurement:[],services:[],disposed:[],lost:[],field:[],summary:{}};let CART=[];let CURRENT_USER=null;let CURRENT_ROLE='user';let CURRENT_TAB='catalog';let DB_REQUESTS=null;let DB_LIVE=false;
const esc=s=>String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]));function formatDateHR(v){if(!v)return '';const s=String(v).trim();let m=s.match(/^(\d{4})-(\d{2})-(\d{2})/);if(m)return `${m[3]}/${m[2]}/${m[1]}`;m=s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);if(m)return `${String(m[1]).padStart(2,'0')}/${String(m[2]).padStart(2,'0')}/${m[3]}`;m=s.match(/^(\d{1,2})\.(\d{1,2})\.(\d{4})\.?$/);if(m)return `${String(m[1]).padStart(2,'0')}/${String(m[2]).padStart(2,'0')}/${m[3]}`;m=s.match(/^(\d{1,2})\/(\d{4})$/);if(m)return `01/${String(m[1]).padStart(2,'0')}/${m[2]}`;m=s.match(/^(\d{1,2})\.(\d{4})\.?$/);if(m)return `01/${String(m[1]).padStart(2,'0')}/${m[2]}`;return s}const canArmory=()=>['admin','oruzar'].includes(CURRENT_ROLE);function toast(t){const e=document.getElementById('toast');e.textContent=t;e.classList.add('show');setTimeout(()=>e.classList.remove('show'),1600)}function badgeClass(s){s=String(s||'').toLowerCase();if(s.includes('nisko')||s.includes('zatra')||s.includes('servis')||s.includes('naru'))return'warn';if(s.includes('nema')||s.includes('rash')||s.includes('izg')||s.includes('odbij')||s.includes('van'))return'danger';return'ok'}function qtyLabel(i){return (i.available_label||i.quantity_label||i.quantity||0)+' '+(i.unit||'')}
function applyRole(){document.body.classList.toggle('role-admin',CURRENT_ROLE==='admin');document.body.classList.toggle('role-oruzar',CURRENT_ROLE==='oruzar');document.body.classList.toggle('role-user',!canArmory());document.querySelector('[data-user-role]').textContent=CURRENT_ROLE;if(!canArmory()&&document.querySelector('.tab.active')?.classList.contains('internal-only'))switchTab('catalog')}
function renderKpis(){const s=DATA.summary||{};const available=DATA.items.reduce((a,i)=>a+(Number(i.available)||0),0);const base=[['🧰','Oprema',s.equipment_count||DATA.items.length],['✅','Dostupno',available],['🪢','Užad',`${s.ropes_count||DATA.ropes.length} / ${Math.round(s.ropes_total_m||0)} m`],['📤','Otvorene posudbe',s.open_loan_count||0],['📋','Inventure',s.inventory_count||DATA.inventories.length],['🛠️','Servis',s.service_count||DATA.services.length]];document.getElementById('kpis').innerHTML=base.map(x=>`<div class="kpi" data-icon="${esc(x[0])}"><small>${esc(x[1])}</small><b>${esc(x[2])}</b></div>`).join('')}
function initFilters(){const cat=document.getElementById('cat');const names=[...new Set(requestableItems().map(displayCategory).filter(Boolean))];cat.innerHTML='<option value="">Sve kategorije</option>'+sortUserCategories(names).map(n=>`<option value="${esc(n)}">${esc(n)}</option>`).join('');['q','cat','avail'].forEach(id=>document.getElementById(id).addEventListener('input',()=>{USER_CAT=null;USER_SUB=null;renderCatalog()}))}
function ropeAsCatalogItem(r){const available=(r.status||'').toLowerCase().includes('društvu')||((r.status||'').toLowerCase().includes('drustvu'));return {id:'ROPE-'+(r.id||r.sku),item_type:'rope',name:r.name||('Uže '+(r.sku||'')),category:'Užad',subcategory:[r.diameter_mm?`Promjer ${r.diameter_mm} mm`:'',r.length_label?`Duljina ${r.length_label} m`:''].filter(Boolean).join(' · '),unit:'kom',tracking_type:'po komadu',quantity:1,quantity_label:available?'1':'0',loaned:0,available:available?1:0,available_label:available?'1':'0',minimum:'',status:available?'aktivno':'nedostupno',availability:available?'dostupno':'nedostupno',member_visible:true,internal_note:`SKU: ${r.sku||''}; lokacija: ${r.location||''}; status: ${r.status||''}`}}
function requestableItems(){return [...(DATA.items||[]),...(DATA.ropes||[]).map(ropeAsCatalogItem)]}

function stripDiacritics(s){return String(s||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim();}
function canonicalArmoryCategory(raw, text){
  const r=stripDiacritics(raw);
  const t=stripDiacritics([raw,text].filter(Boolean).join(' '));
  if(/descender|\bstop\b|simple descender|rig|maestro|id['’]?s|croll|krol|crol|bloker|zumar|žimar|zumar|pojas|sjedal|pedal|stremen|prsni|pupak|pupcano/.test(t)) return 'Osobna oprema';
  if(/uzad|uzetna|\buze\b|\buze |uze |rope|prusik|gurt|traka|kolotur|transportna vreca/.test(t) && !/busil|busilic|busilica|bater|punjac|svrd/.test(t)) return 'Užad i užetna oprema';
  if(/busil|busilic|busilica|aku bus|aku busil|boschhammer|gbh18|gbh180|baterija bosch|punjac za bus|svrd/.test(t)) return 'Bušilice i baterije';
  if(/postavlj|spit|sidrist|ploc|plocic|ring|anker|bolt|karabiner|matica|hms|ok triact|amd/.test(t) && !/descender|croll|bloker|pojas/.test(t)) return 'Oprema za postavljanje';
  if(/crtan|mjeren|disto|kompas|topodroid|dokumentac|nacrt|skic/.test(t)) return 'Oprema za crtanje';
  if(/elektro|foto|kamera|video|rasvjet|svjetl|lampa|ceona|ceo/.test(t)) return 'Elektro i foto oprema';
  if(/medicin|medicina|prva pomoc|prva pom/.test(t)) return 'Medicinska oprema';
  if(/ronil|ronjenje|neopren|mask|peraj|boca/.test(t)) return 'Ronilačka oprema';
  if(/alpinist|alpin|penjack|penjac/.test(t)) return 'Alpinistička oprema';
  if(/cisto podzemlje|ciscenje|cistoc|otpad|vreca za smece/.test(t)) return 'Čisto podzemlje';
  if(/prosir|prosirivanje|klin|cekic|macol|dlijet|štem|stem/.test(t)) return 'Oprema za proširivanje';
  if(/logor|kamp|ekspedic|sator|kuhal|plin|podlog|vreca za spavanje/.test(t)) return 'Oprema za logor';
  if(/alat|kljuc|odvijac|klijest|toolbox/.test(t)) return 'Ostali alat';
  if(/ostalo|razno/.test(r)) return 'Ostalo';
  return raw && String(raw).trim() ? String(raw).trim() : 'Ostalo';
}

function armQtyInt(v,fallback=0){
  if(v===null||v===undefined||v==='') v=fallback;
  let raw=String(v).trim().replace(',','.');
  if(/^\d{1,2}[./]\d{4}$/.test(raw)||/^\d{1,2}[./]\d{1,2}[./]\d{2,4}$/.test(raw)) raw=String(fallback||0);
  let n=Number(raw); if(!Number.isFinite(n)) n=Number(fallback); if(!Number.isFinite(n)) return 0;
  return Math.max(0,Math.round(n));
}
function armQtyFmt(v){return String(armQtyInt(v));}

function normalizeArmoryCategory(x){
  const raw=(x.category||x.category_name||'').trim();
  const text=[x.name,x.model,x.subcategory,raw,x.internal_note,x.note].filter(Boolean).join(' ');
  return canonicalArmoryCategory(raw,text);
}
let USER_CAT=null, USER_SUB=null;
const USER_CATEGORY_ORDER=['Užad i užetna oprema','Oprema za postavljanje','Oprema za crtanje','Osobna oprema - komplet','Osobna oprema','Bušilice i baterije','Elektro i foto oprema','Alpinistička oprema','Ronilačka oprema','Oprema za logor','Oprema za proširivanje','Čisto podzemlje','Medicinska oprema','Ostali alat','Ostalo'];
