(function(){
  const masterTabs=['master','fullinventory','loans','orders','stocktake','procurement','armorySettings'];
  function masterNav(active){
    const item=(id,ico,title,sub)=>`<button class="${active===id?'active':''}" onclick="switchTab('${id}')"><b>${ico} ${title}</b><small>${sub}</small></button>`;
    return `<div class="master-workspace-head"><div><h1>🛡️ Oružar master</h1><p>Ovo je zaseban radni prostor oružara. Ovdje nema članskog kataloga ni “Moje narudžbe” — samo operativa za inventar, posudbe, narudžbe, inventuru, nabave i postavke.</p></div><button class="btn master-back" onclick="exitArmoryMaster()">← Natrag na članove/katalog</button></div><nav class="master-local-nav" aria-label="Oružar master moduli">${item('master','🏠','Pregled','kategorije')}${item('fullinventory','📦','Inventar','stanje')}${item('loans','↔️','Posudbe','vani')}${item('orders','📝','Narudžbe','obrada')}${item('stocktake','✅','Inventura','provjera')}${item('procurement','🛒','Nabave','threshold')}</nav>`;
  }
  window.exitArmoryMaster=function(){document.body.classList.remove('armory-master-active'); if(window.switchTab) switchTab('catalog'); toast('Vraćeno na članski katalog');};
  const prevSwitch=window.switchTab;
  window.switchTab=function(t){
    if(masterTabs.includes(t)){document.body.classList.add('armory-master-active')}else{document.body.classList.remove('armory-master-active')}
    prevSwitch(t);
    if(masterTabs.includes(t)) setTimeout(()=>decorateMasterPane(t),0);
  };
  const prevOpen=window.openArmoryMaster;
  window.openArmoryMaster=function(){if(!canArmory())return toast('Ovaj dio vidi samo oružar/admin'); document.body.classList.add('armory-master-active'); switchTab('master'); window.scrollTo({top:0,behavior:'smooth'}); toast('Oružar master otvoren');};
  function decorateMasterPane(t){
    const el=document.getElementById(t); if(!el || el.dataset.v44Decorated==='1')return;
    el.insertAdjacentHTML('afterbegin', masterNav(t));
    el.dataset.v44Decorated='1';
  }
  const prevRenderMaster=window.renderMaster;
  window.renderMaster=function(){ if(prevRenderMaster)prevRenderMaster(); const el=document.getElementById('master'); if(!el)return; el.dataset.v44Decorated='0'; decorateMasterPane('master'); const oldTitle=el.querySelector('.master-section-title'); if(oldTitle) oldTitle.insertAdjacentHTML('afterend','<div class="master-hint">Prvo odaberi kategoriju opreme. Tek nakon toga se otvaraju podkategorije i moduli. Time oružar ne gleda sve odjednom.</div>'); };
  ['renderFullInventory','renderLoans','renderOrders','renderStocktake','renderProcurement','renderArmorySettings'].forEach(fn=>{
    const prev=window[fn]; if(!prev)return; window[fn]=function(){prev.apply(this,arguments); const map={renderFullInventory:'fullinventory',renderLoans:'loans',renderOrders:'orders',renderStocktake:'stocktake',renderProcurement:'procurement',renderArmorySettings:'armorySettings'}; const id=map[fn]; const el=document.getElementById(id); if(el){el.dataset.v44Decorated='0'; decorateMasterPane(id);} };
  });
  document.addEventListener('DOMContentLoaded',()=>{
    document.querySelectorAll('.tabs .tab[data-tab="catalog"], .tabs .tab[data-tab="myrequests"]').forEach(x=>x.classList.add('member-only-ui'));
    if(location.hash==='#master'||new URLSearchParams(location.search).get('tab')==='master') setTimeout(()=>openArmoryMaster(),120);
  });
})();

;

(function(){
  document.body.classList.add('guest-clean');
  const oldInit = window.initFilters || initFilters;
  window.initFilters = initFilters = function(){
    const cat=document.getElementById('cat');
    const names=[...new Set(requestableItems().map(displayCategory).filter(Boolean))];
    cat.innerHTML='<option value="">Sve kategorije</option>'+sortUserCategories(names).map(n=>`<option value="${esc(n)}">${esc(n)}</option>`).join('');
    ['q','cat'].forEach(id=>document.getElementById(id)?.addEventListener('input',()=>{USER_CAT=null;USER_SUB=null;renderCatalog()}));
    const av=document.getElementById('avail');
    if(av){av.closest('.field').classList.add('internal-only'); av.addEventListener('input',()=>{USER_CAT=null;USER_SUB=null;renderCatalog()});}
  };
  window.userCategoryStats = userCategoryStats = function(){
    const base=requestableItems().filter(i=>(canArmory()||i.member_visible!==false)); const map=new Map();
    base.forEach(i=>{const c=displayCategory(i); if(!map.has(c))map.set(c,{name:c,count:0,available:0,subs:new Set()}); const o=map.get(c); o.count++; o.available+=Number(i.available)||0; o.subs.add(displaySubcategory(i));});
    return sortUserCategories([...map.keys()]).map(k=>map.get(k));
  };
  window.renderCatalog = renderCatalog = function(){
    const all=filteredItems(); const q=document.getElementById('q').value.trim(); const forced=document.getElementById('cat').value; const el=document.getElementById('catalog'); const arm=canArmory();
    if(!USER_CAT&&!q&&!forced){
      const cats=userCategoryStats();
      el.innerHTML=`<div class="user-catalog-head"><div><h2>Odaberi kategoriju opreme</h2><p>Član vidi samo kategorije i artikle za narudžbu. Stanje skladišta i pragove vidi samo oružar.</p></div><button class="btn primary" onclick="document.getElementById('drawer').classList.add('open')">Otvori zahtjev</button></div><div class="user-category-grid">${cats.map(c=>{const m=USER_CATEGORY_META[c.name]||USER_CATEGORY_META['Ostalo'];return `<button class="user-category-card" onclick="selectUserCategory('${esc(c.name)}')"><span class="ico">${m[0]}</span><b>${esc(c.name)}</b><small>${esc(m[1])}</small><small>${esc(c.count)} artikala · ${esc(c.subs.size)} podkategorija</small></button>`}).join('')}</div>`; return;
    }
    const subs=[...new Set(requestableItems().filter(i=>(canArmory()||i.member_visible!==false)&&(!USER_CAT||displayCategory(i)===USER_CAT)&&(!forced||displayCategory(i)===forced)).map(displaySubcategory))].sort((a,b)=>String(a).localeCompare(String(b),'hr'));
    const path=`<div class="user-path"><button onclick="clearUserCategory()">Sve kategorije</button>${USER_CAT?`<button class="active" onclick="clearUserSubcategory()">${esc(USER_CAT)}</button>`:''}${USER_SUB?`<button class="active">${esc(USER_SUB)}</button>`:''}</div>`;
    const subHtml=(USER_CAT&&!USER_SUB&&!q)?`<div class="user-subcat-list">${subs.map(s=>`<button class="user-subcat-card" onclick="selectUserSubcategory('${esc(s)}')">${esc(s)}<small>${requestableItems().filter(i=>(canArmory()||i.member_visible!==false)&&displayCategory(i)===USER_CAT&&displaySubcategory(i)===s).length} artikala</small></button>`).join('')}</div>`:'';
    const note=arm?`<div class="simplified-note">Model v4.47: samo užad ima individualni SKU/kod. Sva ostala oprema je artikl po vrsti + količina.</div>`:'';
    el.innerHTML=`${path}${subHtml}${note}<div class="grid-list">${all.map(i=>{const cat=displayCategory(i);const sub=displaySubcategory(i);const icon=(USER_CATEGORY_META[cat]||USER_CATEGORY_META['Ostalo'])[0];const isRope=(i.item_type==='rope'||cat.includes('Užad'));const detail=arm?`<p class="fineprint">${esc(i.internal_note||'')} ${i.minimum!==''?`Minimum: ${esc(i.minimum)}.`:''}</p><div class="meta"><span class="badge ${Number(i.available)>0?'ok':'warn'}">Dostupno: ${esc(qtyLabel(i))}</span><span class="badge">Ukupno: ${esc(i.quantity_label||i.quantity)}</span><span class="badge">Posuđeno: ${esc(i.loaned||0)}</span>${isRope?`<span class="badge ok">SKU: ${esc(i.sku||i.id)}</span>`:`<span class="badge">Količinski artikl</span>`}</div>`:`<p class="fineprint">${isRope?'Uže se izdaje po konkretnom kodu.':'Artikl se naručuje po vrsti/količini.'}</p>`;return `<article class="item-card"><div class="meta"><span class="badge">${icon} ${esc(cat)}</span><span class="badge">${esc(sub)}</span>${arm?`<span class="badge ${badgeClass(i.status)}">${esc(i.status)}</span>`:''}</div><h3>${esc(i.name)}</h3>${detail}<div class="actions"><button class="btn primary" onclick="addToCart('${esc(i.id)}')">Dodaj u zahtjev</button></div></article>`}).join('')}</div>${!all.length?'<div class="empty">Nema rezultata u ovom izboru.</div>':''}`;
  };
  window.addToCart = addToCart = function(id){const i=requestableItems().find(x=>x.id===id);if(!i)return;const ex=CART.find(x=>x.id===id);if(ex)ex.quantity++;else CART.push({id:i.id,name:i.name,quantity:1,type:i.item_type||'item'});renderRequest();document.getElementById('drawer').classList.add('open');toast('Dodano u zahtjev')};
  window.changeCartQty = changeCartQty = function(id,delta){const ex=CART.find(x=>x.id===id);if(!ex)return;const src=requestableItems().find(x=>x.id===id);const max=canArmory()?Math.max(1,Number(src?.available)||999):999;ex.quantity=Math.max(1,Math.min(max,Number(ex.quantity||1)+delta));renderRequest()};
  window.addCategoryPack = addCategoryPack = function(category){const items=requestableItems().filter(i=>(canArmory()||i.member_visible!==false)&&displayCategory(i)===category);let added=0;items.forEach(i=>{const ex=CART.find(x=>x.id===i.id);if(ex)return;CART.push({id:i.id,name:i.name,quantity:1,type:i.item_type||'item',note:'Paket: '+category});added++});renderRequest();document.getElementById('drawer').classList.add('open');toast(added?'Dodan paket: '+category+' ('+added+')':'Nema stavki za paket')};
  window.manualArmoryPanelHtml = manualArmoryPanelHtml = function(){return `<div class="manual-armory"><div class="manual-hero"><div><span class="badge ok">Manualni put</span><h2>Dodaj / makni opremu bez Excela i SQL-a</h2><p>Samo užad dobiva stvarni pojedinačni kod. Sve ostalo se vodi kao artikl po vrsti i količini.</p></div><button class="btn primary" type="button" onclick="prefillNextSku()">Predloži oznaku</button></div><div class="manual-grid"><form class="manual-card" onsubmit="saveManualEquipment(event)"><h3>+ Nova oprema</h3><label>Što dodaješ?</label><select id="manualKind" onchange="prefillNextSku();toggleManualFields()"><option value="item">Artikl po količini</option><option value="rope">Uže s individualnim kodom</option></select><div class="manual-kind-note" id="manualKindNote">Za artikle app vodi količinu. Ne lijepi se kod na svaki karabiner/croll/descender.</div><label id="manualSkuLabel">Interna oznaka artikla</label><div class="inline-field"><input id="manualSku" placeholder="ART-0001 ili SOV-... za uže"><button class="btn" type="button" onclick="prefillNextSku()">Auto</button></div><div class="item-code-help" id="manualSkuHelp">Kod je samo tehnički ID u bazi, ne mora biti naljepnica na opremi.</div><label>Naziv</label><input id="manualName" required placeholder="npr. Croll, OK karabiner alu, Gilmonte 10.5 mm"><div class="split"><div><label>Kategorija</label><input id="manualCategory" placeholder="Osobna oprema"></div><div><label>Količina</label><input id="manualQty" type="number" min="0" step="1" value="1"></div></div><div class="split rope-only hidden"><div><label>Duljina užeta (m)</label><input id="manualLength" type="number" min="0" step="1"></div><div><label>Promjer užeta (mm)</label><input id="manualDiameter" placeholder="10.5"></div></div><div class="split"><div><label>Proizvođač</label><input id="manualMaker" placeholder="Petzl, Edelrid..."></div><div><label>Model</label><input id="manualModel" placeholder="STOP, CROLL..."></div></div><div class="split"><div><label>Lokacija</label><input id="manualLocation" placeholder="Klaićeva / SOV"></div><div><label>Pregled do</label><input id="manualNextService" type="date"></div></div><label>Napomena</label><textarea id="manualNote" placeholder="Stanje, detalji, provjeriti..."></textarea><button class="btn primary" type="submit">Spremi u evidenciju</button></form><form class="manual-card" onsubmit="retireManualEquipment(event)"><h3>Otpis / van upotrebe</h3><label>Naziv ili kod</label><input id="retireQuery" required placeholder="npr. Croll ili SOV-50M..."><label>Što se dogodilo?</label><select id="retireStatus"><option>Van upotrebe</option><option>Za pregled</option><option>Otpisano</option><option>Izgubljeno</option></select><label>Napomena</label><textarea id="retireNote" placeholder="Zašto, tko, gdje..."></textarea><button class="btn" type="submit">Ažuriraj status</button><p class="fineprint">Nema hard delete. Povijest ostaje, samo se mijenja status/količina.</p></form><div class="manual-card"><h3>Batch količinski unos</h3><p class="fineprint">Za 20 istih karabinera ne generiramo 20 kodova. Samo povećamo količinu artikla ili dodamo novi artikl s količinom.</p><label>Naziv artikla</label><input id="batchName" placeholder="npr. OK karabiner alu"><label>Količina</label><input id="batchCount" type="number" min="1" max="999" value="10"><label>Kategorija</label><input id="batchCategory" placeholder="Oprema za postavljanje"><button class="btn primary" type="button" onclick="saveBatchQuantityItem()">Dodaj količinu</button><div id="batchPreview" class="fineprint"></div></div></div></div>`};
  window.prefillNextSku = prefillNextSku = function(){const k=document.getElementById('manualKind')?.value||'item'; const inp=document.getElementById('manualSku'); if(inp&&!inp.value) inp.value=suggestSku(k==='rope'?'rope':'item')};
  window.toggleManualFields = toggleManualFields = function(){const k=document.getElementById('manualKind')?.value||'item'; document.querySelectorAll('.rope-only').forEach(e=>e.classList.toggle('hidden',k!=='rope')); const q=document.getElementById('manualQty'); if(q) q.disabled=false; const lbl=document.getElementById('manualSkuLabel'); const help=document.getElementById('manualSkuHelp'); const note=document.getElementById('manualKindNote'); if(lbl)lbl.textContent=k==='rope'?'Kod/SKU užeta':'Interna oznaka artikla'; if(help)help.textContent=k==='rope'?'Ovaj kod je stvarni kod užeta i ostaje na užetu.':'Ovo je samo tehnički ID u bazi, ne pojedinačna naljepnica na svakom komadu.'; if(note)note.textContent=k==='rope'?'Užad se vodi pojedinačno po kodu, dužini i promjeru.':'Artikli se vode količinski po vrsti/modelu.';};
  window.suggestSku = suggestSku = function(kind){if(kind==='rope')return 'SOV-'+Date.now().toString().slice(-6); const nums=[...(DATA.items||[])].map(x=>String(x.id||x.legacy_id||'').match(/^ART-(\d+)/)).filter(Boolean).map(m=>Number(m[1])); return 'ART-'+String((Math.max(0,...nums)+1)).padStart(4,'0')};
  window.saveManualEquipment = saveManualEquipment = async function(ev){ev.preventDefault(); if(!canArmory())return toast('Samo admin/oružar'); const kind=document.getElementById('manualKind').value; const sku=(document.getElementById('manualSku').value||suggestSku(kind)).trim(); const qty=Number(document.getElementById('manualQty').value)||1; const row={legacy_id:sku,sku:kind==='rope'?sku:null,catalog_id:sku,name:document.getElementById('manualName').value.trim(),category_name:document.getElementById('manualCategory').value.trim(),category:document.getElementById('manualCategory').value.trim(),subcategory:kind==='rope'?'Statik':'',quantity:qty,quantity_label:String(qty),available:qty,available_label:String(qty),loaned:0,manufacturer:document.getElementById('manualMaker').value.trim(),model:document.getElementById('manualModel').value.trim(),location_name:document.getElementById('manualLocation').value.trim(),location:document.getElementById('manualLocation').value.trim(),next_service:document.getElementById('manualNextService').value||null,note:document.getElementById('manualNote').value.trim(),internal_note:document.getElementById('manualNote').value.trim(),status:'aktivno',availability:'dostupno',tracking_type:kind==='rope'?'po komadu':'po vrsti',unit:kind==='rope'?'m':'kom',member_visible:true,length_m:Number(document.getElementById('manualLength')?.value)||null,diameter_mm:document.getElementById('manualDiameter')?.value||null}; try{if(DB_LIVE&&window.SOVArmoryDB){if(kind==='rope')await SOVArmoryDB.createRope(row); else await SOVArmoryDB.createEquipmentItem(row);} if(kind==='rope')DATA.ropes.unshift({...row,id:sku}); else DATA.items.unshift({...row,id:sku}); renderKpis(); renderCatalog(); if(window.renderFullInventory)renderFullInventory(); mountManualArmoryPanel(); toast('Oprema spremljena'); ev.target.reset(); setTimeout(()=>{prefillNextSku();toggleManualFields()},20);}catch(e){console.error(e);toast('Greška spremanja: '+(e.message||e));}};
  window.saveBatchQuantityItem = async function(){if(!canArmory())return toast('Samo admin/oružar'); const name=document.getElementById('batchName').value.trim(); const count=Math.max(1,Number(document.getElementById('batchCount').value)||1); const category=document.getElementById('batchCategory').value.trim()||selectedCategory||'Ostalo'; if(!name)return toast('Upiši naziv'); let found=DATA.items.find(i=>String(i.name||'').toLowerCase()===name.toLowerCase()&&String(i.category||'')===category); if(found){found.quantity=Number(found.quantity||0)+count; found.available=Number(found.available||0)+count; found.quantity_label=String(found.quantity); found.available_label=String(found.available);} else {const id=suggestSku('item'); found={id,legacy_id:id,catalog_id:id,name,category,category_name:category,subcategory:selectedSubcategory||'',unit:'kom',tracking_type:'po vrsti',quantity:count,quantity_label:String(count),loaned:0,available:count,available_label:String(count),minimum:'',status:'aktivno',availability:'dostupno',member_visible:true,internal_note:'Ručno dodano kroz Oružar master'}; DATA.items.unshift(found);} try{if(DB_LIVE&&window.SOVArmoryDB)await SOVArmoryDB.createEquipmentItem(found);}catch(e){console.warn(e)} document.getElementById('batchPreview').textContent=`Spremljeno: ${name} +${count}`; renderKpis(); if(window.renderFullInventory)renderFullInventory(); toast('Količina dodana');};
  const oldRenderFull=window.renderFullInventory;
  if(oldRenderFull){window.renderFullInventory=function(){oldRenderFull(); const el=document.getElementById('fullinventory'); if(el){el.insertAdjacentHTML('afterbegin','<div class="simplified-note">Pojednostavljeno: kod/SKU je obavezan samo za užad. Ostalo je količinski artikl po vrsti/modelu.</div>');}}}
})();
